}
```
**JavaScript (in script.js file):**
```javascript
// Get the form element
const form = document.getElementById('feedback-form');

// Add an event listener to the form
form.addEventListener('submit', (e) => {
  e.preventDefault();

  // Get the input values
  const name = document.getElementById('name').value;
  const email = document.getElementById('email').value;
  const category = document.getElementById('category').value;
  const text = document.getElementById('text').value;
  const rating = document.getElementById('rating').value;

  // Create a new database entry
  const db = firebase.database();
  const entry = db.ref('feedback').push();
  entry.set({
    user_id: firebase.auth().currentUser.uid,
    category_id: category,
    text: text,
    rating: rating
  });

  // Display a success message
  const result = document.getElementById('result');
  result.innerHTML = `
    <h2>Feedback Submitted!</h2>
    <p>Thank you for submitting your feedback!</p>
  `;
});
```
**Backend Code:**

We'll use Node.js and Express.js to create a backend application that interacts with the database.

**Server Code (in server.js file):**
```javascript
const express = require('express');
const app = express();
const firebase = require('firebase');

// Initialize Firebase
firebase.initializeApp({
  apiKey: 'YOUR_API_KEY',
  authDomain: 'YOUR_AUTH_DOMAIN',
  databaseURL: 'YOUR_DATABASE_URL',
  projectId: 'YOUR_PROJECT_ID',
  storageBucket: 'YOUR_STORAGE_BUCKET',
  messagingSenderId: 'YOUR_MESSAGING_SENDER_ID'
});

// Create a new Express.js route
app.post('/feedback', (req, res) => {
  // Get the input values
  const name = req.body.name;
  const email = req.body.email;
  const category = req.body.category;
  const text = req.body.text;
  const rating = req.body.rating;

  // Create a new database entry
  const db = firebase.database();
  const entry = db.ref('feedback').push();
  entry.set({
    user_id: req.body.user_id,
    category_id: category,
    text: text,
    rating: rating
  });

  // Display a success message
  res.send('Feedback submitted successfully!');
});

// Start the server
app.listen(3000, () => {
  console.log('Server started on port 3000');
});
```
